def get_app_icon(config=None):
    icon_path = get_effective_icon_path(config)
    if icon_path and os.path.exists(icon_path):
        return QIcon(icon_path)
    return QIcon()


def get_app_icon_pixmap(config=None, width=None, height=None):
    icon_path = get_effective_icon_path(config)
    if not icon_path or not os.path.exists(icon_path):
        return QPixmap()
    pixmap = QPixmap(icon_path)
    if pixmap.isNull():
        return QPixmap()
    if width and height:
        return pixmap.scaled(width, height, Qt.KeepAspectRatio, Qt.SmoothTransformation)
    return pixmap


def apply_window_icon(widget, config=None):
    if widget is None:
        return False
    icon = get_app_icon(config)
    if icon.isNull():
        return False
    widget.setWindowIcon(icon)
    return True


def update_icon_label_pixmap(label, config=None, size=None, fallback_text="B"):
    if label is None:
        return
    icon_size = size or label.width() or 32
    pixmap = get_app_icon_pixmap(config, icon_size, icon_size)
    if not pixmap.isNull():
        label.setPixmap(pixmap)
        label.setText("")
        return
    label.setPixmap(QPixmap())
    label.setText(fallback_text)

