global_dpi_scale = 1.0
global_ui_shrink = 1.0

def init_dpi_scale():
    global global_dpi_scale, global_ui_shrink
    
    # 优先使用用户自定义的缩放比例
    try:
        _config = Config()
        custom_scale = _config.get_app_setting("custom_ui_scale", "")
        if custom_scale:
            val = float(custom_scale)
            if 0.5 <= val <= 2.0:
                global_dpi_scale = val
                global_ui_shrink = 1.0
                return
    except Exception:
        pass
    
    # 自动检测DPI
    try:
        from PyQt5.QtWidgets import QApplication
        app = QApplication.instance()
        if app:
            screen = app.primaryScreen()
            if screen:
                dpi = screen.logicalDotsPerInch()
                global_dpi_scale = dpi / 96.0
                global_ui_shrink = max(0.65, 1.0 / (global_dpi_scale ** 0.60))
                return
        import ctypes
        if IS_WINDOWS:
            hdc = ctypes.windll.user32.GetDC(0)
            if hdc:
                dpi = ctypes.windll.gdi32.GetDeviceCaps(hdc, 88)
                ctypes.windll.user32.ReleaseDC(0, hdc)
                if dpi > 0:
                    global_dpi_scale = dpi / 96.0
                    global_ui_shrink = max(0.65, 1.0 / (global_dpi_scale ** 0.60))
                return
    except:
        pass
    global_dpi_scale = 1.0
    global_ui_shrink = 1.0

init_dpi_scale()

def scale(value):
    return int(value * global_dpi_scale * global_ui_shrink)

def scale_style(style_str):
    return re.sub(r'(\d+)px', lambda m: str(scale(int(m.group(1)))) + 'px', style_str)

