    update_progress_signal = pyqtSignal(int, str)
    add_log_signal = pyqtSignal(str)
    stop_signal = pyqtSignal()       # 停止：保留已解析结果
    cancel_signal = pyqtSignal()     # 取消：清空并退出
    
