def _markdown_to_html(text):
    """将Markdown文本转换为HTML，用于QTextBrowser渲染"""
    if not text or not text.strip():
        return ""

    lines = text.split('\n')
    result = []
    in_ul = False
    in_ol = False
    in_bq = False
    in_code = False
    code_buf = []
    bq_lines = []

    for line in lines:
        # 代码块
        if line.strip().startswith('```'):
            # 先关闭引用块（如果在引用中）
            if in_bq:
                result.append('<br>'.join(bq_lines))
                result.append('</blockquote>')
                in_bq = False; bq_lines = []
            _close_lists(result, in_ul, in_ol)
            in_ul = in_ol = False
            if in_code:
                result.append('</code></pre>')
                in_code = False
            else:
                result.append('<pre style="background:#f5f5f5;border-radius:4px;padding:10px;margin:6px 0;overflow-x:auto;font-family:Consolas,monospace;font-size:12px;line-height:1.5"><code>')
                in_code = True
            continue

        if in_code:
            escaped = line.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;')
            code_buf.append(escaped)
            continue

        # 引用块 >
        bq_m = re.match(r'^>\s?(.*)', line)
        if bq_m:
            if not in_bq:
                _close_lists(result, in_ul, in_ol)
                in_ul = in_ol = False
                in_bq = True
                bq_lines = []
            content = bq_m.group(1).strip()
            bq_lines.append(_md_inline(content) if content else '<br>')
            continue
        else:
            # 非引用行：关闭引用块
            if in_bq:
                result.append('<br>'.join(bq_lines))
                result.append('</blockquote>')
                in_bq = False; bq_lines = []

        # 标题
        m = re.match(r'^(#{1,3})\s+(.+)', line)
        if m:
            _close_lists(result, in_ul, in_ol)
            in_ul = in_ol = False
            level = len(m.group(1))
            content = _md_inline(m.group(2))
            sizes = {1: ('18px', '#cf1322', '600'), 2: ('15px', '#1677ff', '600'), 3: ('14px', '#262626', '600')}
            fs, fc, fw = sizes.get(level, ('13px', '#595959', 'normal'))
            margin_val = 12 - level
            result.append(f'<h{level} style="margin:{margin_val}px 0 6px;font-size:{fs};color:{fc};font-weight:{fw}">{content}</h{level}>')
            continue

        # 分割线
        if re.match(r'^[-*_]{3,}\s*$', line.strip()):
            _close_lists(result, in_ul, in_ol)
            in_ul = in_ol = False
            result.append('<hr style="border:none;border-top:1px solid #e8e8e8;margin:10px 0">')
            continue

        # 无序列表：- 或 • 或 *
        m = re.match(r'^(\s*)[-•*]\s+(.+)', line)
        if m:
            if not in_ul:
                if in_ol:
                    result.append('</ol>'); in_ol = False
                result.append('<ul style="margin:4px 0;padding-left:22px">')
                in_ul = True
            indent = len(m.group(1))
            pad = f'margin-left:{indent * 20}px;' if indent else ''
            result.append(f'<li style="margin:3px 0;line-height:1.7;color:#434343;{pad}">{_md_inline(m.group(2))}</li>')
            continue

        # 有序列表
        m = re.match(r'^(\s*)(\d+)\.\s+(.+)', line)
        if m:
            if not in_ol:
                if in_ul:
                    result.append('</ul>'); in_ul = False
                result.append('<ol style="margin:4px 0;padding-left:22px">')
                in_ol = True
            result.append(f'<li style="margin:3px 0;line-height:1.7;color:#434343">{_md_inline(m.group(3))}</li>')
            continue

        # 普通段落
        stripped = line.strip()
        if not stripped:
            _close_lists(result, in_ul, in_ol)
            in_ul = in_ol = False
            continue

        result.append(f'<p style="margin:3px 0;line-height:1.7;color:#434343">{_md_inline(stripped)}</p>')

    # 收尾
    if in_bq and bq_lines:
        result.append('<br>'.join(bq_lines))
        result.append('</blockquote>')
    if in_code and code_buf:
        result.append('\n'.join(code_buf))
        result.append('</code></pre>')
    _close_lists(result, in_ul, in_ol)

    body = '\n'.join(result)
    return f'<html><body style="font-family:\'Microsoft YaHei\',\'Segoe UI\',sans-serif;font-size:13px;color:#434343;line-height:1.7;padding:4px 0">{body}</body></html>'


def _md_inline(text):
    """处理行内的Markdown语法（先转义原文，再生成标签）"""

    # 1. 先全局转义所有特殊字符（在生成任何标签之前）
    text = text.replace('&', '&amp;')
    text = text.replace('<', '&lt;')
    text = text.replace('>', '&gt;')

    # 2. 链接 [text](url) —— 先处理，避免和加粗冲突
    def _link_repl(m):
        link_text = m.group(1)  # 已被转义
        url = m.group(2).replace('&amp;', '&')  # URL中的&恢复原样
        return (f'<a href="{url}" '
                f'style="color:#1677ff;text-decoration:none;'
                f'border-bottom:1px solid rgba(22,119,255,0.3)">{link_text}</a>')
    text = re.sub(r'\[([^\]]+)\]\(([^)]+)\)', _link_repl, text)

    # 3. 加粗 **text**
    def _bold_repl(m):
        inner = m.group(1)  # 已被转义
        return f'<b style="color:#262626">{inner}</b>'
    text = re.sub(r'\*\*(.+?)\*\*', _bold_repl, text)

    # 4. 斜体 *text*（排除已经是加粗的 **）
    def _italic_repl(m):
        inner = m.group(1)  # 已被转义
        return f'<i>{inner}</i>'
    text = re.sub(r'(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)', _italic_repl, text)

    # 5. 行内代码 `code`
    def _code_repl(m):
        inner = m.group(1)  # 已被转义
        return (f'<code style="background:#f0f0f0;border-radius:3px;'
                f'padding:1px 5px;font-size:12px;'
                f'font-family:Consolas,monospace;color:#d63384">{inner}</code>')
    text = re.sub(r'`([^`]+)`', _code_repl, text)

    # 不需要再转义了，所有文本内容已在步骤1中完成转义

    return text


def _close_lists(result, in_ul, in_ol):
    if in_ul:
        result.append('</ul>')
    if in_ol:
        result.append('</ol>')


