        deselect_all_btn = QPushButton("取消全选")
        deselect_all_btn.setMinimumHeight(scale(36))
        deselect_all_btn.setMinimumWidth(scale(100))
        deselect_all_btn.clicked.connect(self.deselect_all)
        
