    def _on_widget_clicked(self, event, checkbox, ep):
        if ep.get('permission_denied', False) and not ep.get('has_free_part', False):
            return
        if not checkbox.geometry().contains(checkbox.mapFromParent(event.pos())):
            checkbox.setChecked(not checkbox.isChecked())

    def create_episode_widget(self, ep, index, permission_denied=False):
        widget = QWidget()
        layout = QHBoxLayout(widget)
        layout.setContentsMargins(scale(10), scale(8), scale(10), scale(8))
        layout.setSpacing(scale(12))
        
        checkbox = QCheckBox()
        checkbox.setChecked(index in self.selected_indices)
        checkbox.setMinimumSize(scale(22), scale(22))
        checkbox.stateChanged.connect(lambda state, idx=index: self.on_checkbox_changed(state, idx))
        if permission_denied:
            checkbox.setDisabled(True)
        layout.addWidget(checkbox, alignment=Qt.AlignCenter)
        
        cover_label = QLabel()
        cover_label.setMinimumSize(scale(96), scale(64))
        cover_label.setMaximumSize(scale(120), scale(80))
        cover_label.setStyleSheet(scale_style("border: 1px solid #e2e8f0; border-radius: 6px; background-color: #f1f5f9;"))
        cover_label.setAlignment(Qt.AlignCenter)
        cover_label.setText("无封面")
        layout.addWidget(cover_label)
        
        cover_url = ep.get('cover', '')
        if cover_url:
            def load_cover():
                class CoverLoader(QThread):
                    class SignalEmitter(QObject):
                        finished = pyqtSignal(QPixmap, int)
                    
                    def __init__(self, url, label_index):
                        super().__init__()
                        self.url = url
                        self.label_index = label_index
                        self.signals = self.SignalEmitter()
                    
                    def run(self):
                        pixmap = QPixmap()
                        for attempt in range(2):
                            try:
                                response = requests.get(self.url, headers=_COVER_HEADERS, timeout=10)
                                response.raise_for_status()
                                pixmap = QPixmap()
                                pixmap.loadFromData(response.content)
                                if not pixmap.isNull():
                                    break
                            except Exception:
                                if attempt == 0:
                                    continue
                        self.signals.finished.emit(pixmap, self.label_index)
                
                def on_cover_loaded(pixmap, label_index):
                    try:
                        if not pixmap.isNull():
                            scaled_pixmap = pixmap.scaled(scale(120), scale(80), Qt.KeepAspectRatio, Qt.SmoothTransformation)
                            cover_label.setPixmap(scaled_pixmap)
                            cover_label.setStyleSheet(scale_style("border: 1px solid #e2e8f0; border-radius: 6px;"))
                        else:
                            cover_label.setText("加载失败")
                    except Exception:
                        pass
                    finally:
                        self.active_loaders -= 1
                        self.process_pending_cover_loading()
                
                def start_loader():
                    if self.active_loaders < self.max_loaders:
                        self.active_loaders += 1
                        loader = CoverLoader(cover_url, index)
                        self.cover_loaders.append(loader)
                        loader.signals.finished.connect(on_cover_loaded)
                        loader.start()
                    else:
                        self.pending_cover_loading.append((cover_url, cover_label, scale(120), scale(80), False))
                
                start_loader()
            
            QTimer.singleShot(10 * index, load_cover)
        
        info_layout = QVBoxLayout()
        info_layout.setSpacing(scale(3))
        
        if self.is_bangumi:
            title = f"{ep.get('ep_index', '')} - {ep.get('ep_title', '')}"
        else:
            if 'page' in ep and 'title' in ep:
                title = f"第{ep['page']}集 - {ep['title']}"
            elif 'ep_index' in ep and 'ep_title' in ep:
                title = f"{ep['ep_index']} - {ep['ep_title']}"
            else:
                title = f"第{index+1}集"
        
        title_label = QLabel(title)
        if permission_denied and not ep.get('has_free_part', False):
            title_label.setStyleSheet(scale_style("font-weight: 500; font-size: 14px; color: #94a3b8;"))
        else:
            title_label.setStyleSheet(scale_style("font-weight: 500; font-size: 14px;"))
        title_label.setWordWrap(True)
        info_layout.addWidget(title_label)
        
        meta_layout = QHBoxLayout()
        meta_layout.setSpacing(scale(12))
        
        duration = ep.get('duration_str', '') or ep.get('duration', '')
        if duration:
            if isinstance(duration, int):
                hours = duration // 3600
                minutes = (duration % 3600) // 60
                seconds = duration % 60
                if hours > 0:
                    duration_str = f"{hours:02d}:{minutes:02d}:{seconds:02d}"
                else:
                    duration_str = f"{minutes:02d}:{seconds:02d}"
            else:
                duration_str = str(duration)
            dur_label = QLabel(f"时长 {duration_str}")
            dur_label.setStyleSheet(scale_style("font-size: 11px; color: #64748b;"))
            meta_layout.addWidget(dur_label)
        
        if permission_denied:
            if ep.get('has_free_part', False):
                perm_label = QLabel("试看")
                perm_label.setStyleSheet(scale_style("font-size: 11px; color: #10b981; font-weight: 500; border: 1px solid #10b981; border-radius: 3px; padding: 0 4px;"))
            else:
                perm_label = QLabel("付费")
                perm_label.setStyleSheet(scale_style("font-size: 11px; color: #f56c6c; font-weight: 500; border: 1px solid #f56c6c; border-radius: 3px; padding: 0 4px;"))
            meta_layout.addWidget(perm_label)
        
        meta_layout.addStretch(1)
        info_layout.addLayout(meta_layout)
        
        layout.addLayout(info_layout, stretch=1)
        
        widget.mousePressEvent = lambda event, cb=checkbox: self._on_widget_clicked(event, cb, ep)
        
        return widget

    def create_episode_card(self, ep, index):
        cw = self._card_w_int
        ch = self._card_h_int
        cover_h = ch - scale(55)  # 封面高度 = 总高 - 标题区
        widget = QWidget()
        widget.setFixedSize(cw, ch)
        widget.setStyleSheet(scale_style("""
            QWidget {
                background-color: white;
                border-radius: 8px;
            }
        """))

        layout = QVBoxLayout(widget)
        layout.setContentsMargins(scale(0), scale(0), scale(0), scale(0))
        layout.setSpacing(scale(0))


        cover_container = QWidget()
        cover_container.setFixedSize(cw, cover_h)
        cover_container.setStyleSheet(scale_style("""
            QWidget {
                border-radius: 8px 8px 0 0;
                background-color: #f1f5f9;
            }
        """))
        cover_layout = QVBoxLayout(cover_container)
        cover_layout.setContentsMargins(0, 0, 0, 0)
        cover_layout.setSpacing(0)


        cover_label = QLabel(cover_container)
        cover_label.setGeometry(0, 0, cw, cover_h)
        cover_label.setStyleSheet("border: none;")
        cover_label.setAlignment(Qt.AlignCenter)
        cover_label.setText("")

        checkbox = QCheckBox(cover_container)
        checkbox.setChecked(index in self.selected_indices)
        checkbox.stateChanged.connect(lambda state, idx=index: self.on_checkbox_changed(state, idx))
        checkbox.setStyleSheet(scale_style("""
            QCheckBox::indicator {
                width: 18px;
                height: 18px;
            }
        """))
        checkbox.setGeometry(scale(6), scale(6), scale(18), scale(18))
        checkbox.raise_()


        duration = ep.get('duration_str', '') or ep.get('duration', '')
        if duration:
            if isinstance(duration, int):

                hours = duration // 3600
                minutes = (duration % 3600) // 60
                seconds = duration % 60
                if hours > 0:
                    duration_str = f"{hours:02d}:{minutes:02d}:{seconds:02d}"
                else:
                    duration_str = f"{minutes:02d}:{seconds:02d}"
            else:
                duration_str = str(duration)

            duration_label = QLabel(duration_str, cover_container)
            duration_label.setStyleSheet(scale_style("""
                QLabel {
                    background-color: rgba(0, 0, 0, 0.7);
                    color: white;
                    padding: 2px 6px;
                    border-radius: 4px;
                    font-size: 11px;
                    font-weight: 500;
                }
            """))
            duration_label.adjustSize()
            duration_label.move(cw - duration_label.width() - scale(6), cover_h - duration_label.height() - scale(6))
            duration_label.raise_()

        layout.addWidget(cover_container)


        cover_url = ep.get('cover', '')
        if cover_url:

            def load_cover():

                class CoverLoader(QThread):
                    class SignalEmitter(QObject):
                        finished = pyqtSignal(QPixmap, int)

                    def __init__(self, url, label_index):
                        super().__init__()
                        self.url = url
                        self.label_index = label_index
                        self.signals = self.SignalEmitter()

                    def run(self):
                        pixmap = QPixmap()
                        for attempt in range(2):
                            try:
                                response = requests.get(self.url, headers=_COVER_HEADERS, timeout=10)
                                response.raise_for_status()
                                pixmap = QPixmap()
                                pixmap.loadFromData(response.content)
                                if not pixmap.isNull():
                                    break
                            except Exception:
                                if attempt == 0:
                                    continue
                        self.signals.finished.emit(pixmap, self.label_index)

                def on_cover_loaded(pixmap, label_index):
                    try:
                        if not pixmap.isNull():
                            target_w = cw
                            target_h = cover_h
                            scaled_pixmap = pixmap.scaled(target_w, target_h, Qt.KeepAspectRatioByExpanding, Qt.SmoothTransformation)
                            crop_w = min(scaled_pixmap.width(), target_w)
                            crop_h = min(scaled_pixmap.height(), target_h)
                            x = (scaled_pixmap.width() - crop_w) // 2
                            y = (scaled_pixmap.height() - crop_h) // 2
                            cropped = scaled_pixmap.copy(x, y, crop_w, crop_h)
                            cover_label.setPixmap(cropped)
                            cover_label.setStyleSheet("border: none;")
                    except Exception:
                        pass
                    finally:

                        self.active_loaders -= 1

                        self.process_pending_cover_loading()

                def start_loader():
                    if self.active_loaders < self.max_loaders:
                        self.active_loaders += 1
                        loader = CoverLoader(cover_url, index)
                        self.cover_loaders.append(loader)
                        loader.signals.finished.connect(on_cover_loaded)
                        loader.start()
                    else:

                        self.pending_cover_loading.append((cover_url, cover_label, cw, cover_h, True))

                start_loader()


            QTimer.singleShot(10 * index, load_cover)


        title_container = QWidget()
        title_layout = QVBoxLayout(title_container)
        title_layout.setContentsMargins(scale(8), scale(6), scale(8), scale(8))
        title_layout.setSpacing(scale(3))


        if self.is_bangumi:
            episode_num = ep.get('ep_index', f"第{index+1}集")
        else:
            if 'page' in ep:
                episode_num = f"第{ep['page']}集"
            elif 'ep_index' in ep:
                episode_num = ep['ep_index']
            else:
                episode_num = f"第{index+1}集"

        episode_label = QLabel(episode_num)
        episode_label.setStyleSheet(scale_style("""
            QLabel {
                color: #737373;
                font-size: 11px;
                font-weight: 500;
            }
        """))
        title_layout.addWidget(episode_label)


        if self.is_bangumi:
            title = ep.get('ep_title', "")
        else:
            if 'title' in ep:
                title = ep['title']
            elif 'ep_title' in ep:
                title = ep['ep_title']
            else:
                title = ""

        title_label = _EpMarqueeLabel(title, display_w=cw - scale(12))
        title_label.setFixedSize(cw - scale(12), scale(20))
        title_label.setStyleSheet(scale_style("""
            QLabel {
                font-size: 12px;
                font-weight: 500;
                color: #1f2937;
                background: transparent;
            }
        """))
        title_layout.addWidget(title_label)
        
        layout.addWidget(title_container)
        
        widget.mousePressEvent = lambda event, cb=checkbox: self._on_widget_clicked(event, cb, ep)
        
        return widget

    def populate_list_view(self):
        self.list_view.clear()
        
        
        self.pending_cover_loading.clear()
        self.active_loaders = 0
        
        
        self.loaded_episodes = 0
        
        
        
        def create_item(i):
            if i >= len(self.filtered_episodes) or i >= self.loaded_episodes + self.batch_size:
                return
            
            ep = self.filtered_episodes[i]
            
            original_index = self.episodes.index(ep)
            item = QListWidgetItem()
            item_widget = self.create_episode_widget(ep, original_index, ep.get('permission_denied', False))
            
            item.setSizeHint(QSize(scale(0), scale(110)))
            item.setData(Qt.UserRole, original_index)
            
            if ep.get('permission_denied', False):
                has_free_part = ep.get('has_free_part', False)
                if has_free_part:
                    free_duration = ep.get('free_duration', 0)
                    if free_duration > 0:
                        for i in range(item_widget.layout().count()):
                            widget = item_widget.layout().itemAt(i).widget()
                            if isinstance(widget, QVBoxLayout):
                                for j in range(widget.count()):
                                    label = widget.itemAt(j).widget()
                                    if isinstance(label, QLabel) and label.text().startswith('时长'):
                                        hours = free_duration // 3600
                                        minutes = (free_duration % 3600) // 60
                                        seconds = free_duration % 60
                                        if hours > 0:
                                            duration_str = f"{hours:02d}:{minutes:02d}:{seconds:02d}"
                                        else:
                                            duration_str = f"{minutes:02d}:{seconds:02d}"
                                        label.setText(f"试看 {duration_str}")
                                        label.setStyleSheet(scale_style("font-size: 11px; color: #10b981;"))
                else:
                    item.setFlags(item.flags() & ~Qt.ItemIsEnabled)
                    item_widget.setStyleSheet("QWidget { opacity: 0.5; }")
            
            self.list_view.addItem(item)
            self.list_view.setItemWidget(item, item_widget)
            
            
            QTimer.singleShot(0, lambda: create_item(i + 1))
        
        
        if self.filtered_episodes:
            create_item(0)
            self.loaded_episodes = min(self.batch_size, len(self.filtered_episodes))
        
        
        def on_scroll_bar_value_changed(value):
            scroll_bar = self.list_view.verticalScrollBar()
            if value >= scroll_bar.maximum() - 200 and self.loaded_episodes < len(self.filtered_episodes):
                
                start = self.loaded_episodes
                end = min(start + self.batch_size, len(self.filtered_episodes))
                
                def load_more(i):
                    if i >= end:
                        return
                    
                    ep = self.filtered_episodes[i]
                    
                    original_index = self.episodes.index(ep)
                    item = QListWidgetItem()
                    item_widget = self.create_episode_widget(ep, original_index, ep.get('permission_denied', False))
                    
                    item.setSizeHint(QSize(scale(0), scale(110)))
                    item.setData(Qt.UserRole, original_index)
                    
                    if ep.get('permission_denied', False):
                        item.setFlags(item.flags() & ~Qt.ItemIsEnabled)
                        item_widget.setStyleSheet("QWidget { opacity: 0.5; }")
                    
                    self.list_view.addItem(item)
                    self.list_view.setItemWidget(item, item_widget)
                    
                    
                    QTimer.singleShot(0, lambda: load_more(i + 1))
                
                load_more(start)
                self.loaded_episodes = end
        
        
        self.list_view.verticalScrollBar().valueChanged.connect(on_scroll_bar_value_changed)

    def populate_card_view(self):
        self.card_view.clear()
        
        
        self.pending_cover_loading.clear()
        self.active_loaders = 0
        
        
        self.loaded_episodes = 0
        
        
        
        def create_item(i):
            if i >= len(self.filtered_episodes) or i >= self.loaded_episodes + self.batch_size:
                return
            
            ep = self.filtered_episodes[i]
            
            original_index = self.episodes.index(ep)
            item = QListWidgetItem()
            item_widget = self.create_episode_card(ep, original_index)
            item.setSizeHint(QSize(scale(200), scale(170)))
            item.setData(Qt.UserRole, original_index)
            
            if ep.get('permission_denied', False):
                # 检查是否有免费部分
                has_free_part = ep.get('has_free_part', False)
                if has_free_part:
                    # 有免费部分，保持亮色，但显示免费时长
                    free_duration = ep.get('free_duration', 0)
                    if free_duration > 0:
                        # 更新时长显示为免费时长
                        for i in range(item_widget.layout().count()):
                            widget = item_widget.layout().itemAt(i).widget()
                            if isinstance(widget, QVBoxLayout):
                                for j in range(widget.count()):
                                    label = widget.itemAt(j).widget()
                                    if isinstance(label, QLabel) and label.text().startswith('时长:'):
                                        # 计算免费时长
                                        hours = free_duration // 3600
                                        minutes = (free_duration % 3600) // 60
                                        seconds = free_duration % 60
                                        if hours > 0:
                                            duration_str = f"{hours:02d}:{minutes:02d}:{seconds:02d}"
                                        else:
                                            duration_str = f"{minutes:02d}:{seconds:02d}"
                                        label.setText(f"免费时长: {duration_str}")
                                        label.setStyleSheet(scale_style("font-size: 11px; color: #10b981;"))
                else:
                    # 完全权限不足，变灰
                    item.setFlags(item.flags() & ~Qt.ItemIsEnabled)
                    item_widget.setStyleSheet("opacity: 0.6;")
            
            self.card_view.addItem(item)
            self.card_view.setItemWidget(item, item_widget)
            
            
            QTimer.singleShot(0, lambda: create_item(i + 1))
        
        
        if self.filtered_episodes:
            create_item(0)
            self.loaded_episodes = min(self.batch_size, len(self.filtered_episodes))
        
        
        def on_scroll_bar_value_changed(value):
            scroll_bar = self.card_view.verticalScrollBar()
            if value >= scroll_bar.maximum() - 200 and self.loaded_episodes < len(self.filtered_episodes):
                
                start = self.loaded_episodes
                end = min(start + self.batch_size, len(self.filtered_episodes))
                
                def load_more(i):
                    if i >= end:
                        return
                    
                    ep = self.filtered_episodes[i]
                    
                    original_index = self.episodes.index(ep)
                    item = QListWidgetItem()
                    item_widget = self.create_episode_card(ep, original_index)
                    item.setSizeHint(QSize(scale(200), scale(170)))
                    item.setData(Qt.UserRole, original_index)
                    
                    if ep.get('permission_denied', False):
                        item.setFlags(item.flags() & ~Qt.ItemIsEnabled)
                        item_widget.setStyleSheet("opacity: 0.6;")
                    
                    self.card_view.addItem(item)
                    self.card_view.setItemWidget(item, item_widget)
                    
                    
                    QTimer.singleShot(0, lambda: load_more(i + 1))
                
                load_more(start)
                self.loaded_episodes = end
        
        
        self.card_view.verticalScrollBar().valueChanged.connect(on_scroll_bar_value_changed)

    def filter_episodes(self, keyword):
        keyword = keyword.lower()
        
        selected_indices = list(self.selected_indices)

        if not keyword:
            self.filtered_episodes = self.episodes.copy()
        else:
            self.filtered_episodes = [
                ep for ep in self.episodes
                if keyword in (ep.get('ep_title', '').lower() if self.is_bangumi else ep.get('title', '').lower())
            ]

        # 应用排序
        self.apply_sort()

        if self.list_radio.isChecked():
            self.populate_list_view()
        else:
            self.populate_card_view()
    
    def on_sort_changed(self, index):
        sort_options = ["index", "title"]
        if index < len(sort_options):
            self.current_sort = sort_options[index]
            self.apply_sort()
            if self.list_radio.isChecked():
                self.populate_list_view()
            else:
                self.populate_card_view()
    
    def apply_sort(self):
        if self.current_sort == "index":
            # 按集数排序
            def get_episode_index(ep):
                # 尝试获取page或ep_index
                page = ep.get('page')
                if page:
                    try:
                        return int(page)
                    except:
                        pass
                ep_index = ep.get('ep_index')
                if ep_index:
                    try:
                        return int(ep_index)
                    except:
                        pass
                return 0
            self.filtered_episodes.sort(key=get_episode_index)
        elif self.current_sort == "title":
            # 按标题排序
            self.filtered_episodes.sort(key=lambda x: x.get('title', '') or x.get('ep_title', ''))

    def switch_view(self, view_type):
        
        selected_indices = list(self.selected_indices)

        if view_type == "list":
            self.stacked_view.setCurrentWidget(self.list_view)
            self.populate_list_view()
        else:
            self.stacked_view.setCurrentWidget(self.card_view)
            self.populate_card_view()
    
    def on_checkbox_changed(self, state, index):
        ep = self.episodes[index]
        if ep.get('permission_denied', False) and not ep.get('has_free_part', False):
            return
        if state == Qt.Checked:
            self.selected_indices.add(index)
        else:
            self.selected_indices.discard(index)
        self._update_count_label()
    
    def _update_count_label(self):
        try:
            if hasattr(self, 'count_label'):
                self.count_label.setText(f"已选 {len(self.selected_indices)}/{len(self.episodes)} 集")
        except Exception:
            pass
    
    def process_pending_cover_loading(self):
        while self.pending_cover_loading and self.active_loaders < self.max_loaders:
            cover_url, cover_label, target_w, target_h, use_crop = self.pending_cover_loading.pop(0)
            self.active_loaders += 1
            
            
            class CoverLoader(QThread):
                class SignalEmitter(QObject):
                    finished = pyqtSignal(QPixmap)
                
                def __init__(self, url):
                    super().__init__()
                    self.url = url
                    self.signals = self.SignalEmitter()
                
                def run(self):
                    pixmap = QPixmap()
                    for attempt in range(2):
                        try:
                            response = requests.get(self.url, headers=_COVER_HEADERS, timeout=10)
                            response.raise_for_status()
                            pixmap = QPixmap()
                            pixmap.loadFromData(response.content)
                            if not pixmap.isNull():
                                break
                        except Exception:
                            if attempt == 0:
                                continue
                    self.signals.finished.emit(pixmap)
            
            def on_cover_loaded(pixmap):
                try:
                    if not pixmap.isNull():
                        if use_crop:
                            scaled_pixmap = pixmap.scaled(target_w, target_h, Qt.KeepAspectRatioByExpanding, Qt.SmoothTransformation)
                            crop_w = min(scaled_pixmap.width(), target_w)
                            crop_h = min(scaled_pixmap.height(), target_h)
                            x = (scaled_pixmap.width() - crop_w) // 2
                            y = (scaled_pixmap.height() - crop_h) // 2
                            cropped = scaled_pixmap.copy(x, y, crop_w, crop_h)
                            cover_label.setPixmap(cropped)
                            cover_label.setStyleSheet("border: none;")
                        else:
                            scaled_pixmap = pixmap.scaled(target_w, target_h, Qt.KeepAspectRatio, Qt.SmoothTransformation)
                            cover_label.setPixmap(scaled_pixmap)
                            cover_label.setStyleSheet(scale_style("border: 1px solid #e2e8f0; border-radius: 6px;"))
                    else:
                        cover_label.setText("加载失败")
                except Exception:
                    pass
                finally:
                    
                    self.active_loaders -= 1
                    
                    self.process_pending_cover_loading()
            
            loader = CoverLoader(cover_url)
            self.cover_loaders.append(loader)
            loader.signals.finished.connect(on_cover_loaded)
            loader.start()

    def select_all(self):
        current_view = self.list_view if self.list_radio.isChecked() else self.card_view
        for i in range(current_view.count()):
            item = current_view.item(i)
            index = item.data(Qt.UserRole)
            ep = self.episodes[index]
            if ep.get('permission_denied', False) and not ep.get('has_free_part', False):
                continue
            self.selected_indices.add(index)
            
            widget = current_view.itemWidget(item)
            if widget:
                for child in widget.findChildren(QCheckBox):
                    child.setChecked(True)
        self._update_count_label()

    def deselect_all(self):
        current_view = self.list_view if self.list_radio.isChecked() else self.card_view
        for i in range(current_view.count()):
            item = current_view.item(i)
            index = item.data(Qt.UserRole)
            self.selected_indices.discard(index)
            
            widget = current_view.itemWidget(item)
            if widget:
                for child in widget.findChildren(QCheckBox):
                    child.setChecked(False)
        self._update_count_label()

    def invert_selection(self):
        current_view = self.list_view if self.list_radio.isChecked() else self.card_view
        for i in range(current_view.count()):
            item = current_view.item(i)
            index = item.data(Qt.UserRole)
            ep = self.episodes[index]
            if ep.get('permission_denied', False) and not ep.get('has_free_part', False):
                continue
            if index in self.selected_indices:
                self.selected_indices.discard(index)
            else:
                self.selected_indices.add(index)
            widget = current_view.itemWidget(item)
            if widget:
                for child in widget.findChildren(QCheckBox):
                    child.setChecked(index in self.selected_indices)
        self._update_count_label()

    def select_range(self):
        from PyQt5.QtWidgets import QInputDialog
        total = len(self.episodes)
        text, ok = QInputDialog.getText(
            self, "选择范围",
            f"共 {total} 集，输入范围（如: 1-10 或 1,3,5,7-9）：",
        )
        if not ok or not text.strip():
            return
        indices = set()
        try:
            for part in text.strip().split(','):
                part = part.strip()
                if '-' in part:
                    bounds = part.split('-', 1)
                    start = int(bounds[0].strip())
                    end = int(bounds[1].strip())
                    for n in range(start, end + 1):
                        if 1 <= n <= total:
                            indices.add(n - 1)
                else:
                    n = int(part)
                    if 1 <= n <= total:
                        indices.add(n - 1)
        except (ValueError, IndexError):
            self.show_notification("格式错误，请输入如 1-10 或 1,3,5,7-9", "warning")
            return
        
        if not indices:
            self.show_notification("没有有效的集数", "warning")
            return
        
        for idx in indices:
            ep = self.episodes[idx]
            if not (ep.get('permission_denied', False) and not ep.get('has_free_part', False)):
                self.selected_indices.add(idx)
        
        current_view = self.list_view if self.list_radio.isChecked() else self.card_view
        for i in range(current_view.count()):
            item = current_view.item(i)
            index = item.data(Qt.UserRole)
            if index in self.selected_indices:
                widget = current_view.itemWidget(item)
                if widget:
                    for child in widget.findChildren(QCheckBox):
                        child.setChecked(True)
        self._update_count_label()

    def accept(self):
        
        self.selected_episodes = [self.episodes[i] for i in sorted(self.selected_indices)]
        super().accept()
    
    def mousePressEvent(self, event):
        
        if event.button() == Qt.LeftButton:
            self.drag_position = event.globalPos() - self.frameGeometry().topLeft()
            event.accept()

    def mouseMoveEvent(self, event):
        if event.buttons() == Qt.LeftButton and hasattr(self, 'drag_position') and self.drag_position is not None:
            self.move(event.globalPos() - self.drag_position)
            event.accept()

    def mouseReleaseEvent(self, event):
        
        self.drag_position = None
        event.accept()

    def closeEvent(self, event):
        try:
            geo = self.geometry()
            self.config.set_app_setting("window_geometry", f"{geo.x()},{geo.y()},{geo.width()},{geo.height()}")
        except Exception:
            pass
        try:
            for loader in self.cover_loaders:
                if loader.isRunning():
                    loader.terminate()
                    loader.wait(100)
            self.cover_loaders.clear()
        except Exception:
            pass
        try:
            super().closeEvent(event)
        except Exception:
            event.accept()

    def _recalc_grid(self, win_w):
        """根据窗口宽度计算最优列数和卡片宽度，确保刚好填满不留空"""
        avail = win_w - self._card_margin * 2
        self._cols = 4
        for c in [5, 4]:
            cw = (avail - (c - 1) * self._card_spacing) / c
            if cw >= self._min_card_w:
                self._cols = c
                break
        self._card_w = (avail - (self._cols - 1) * self._card_spacing) / self._cols
        # 卡片高度按封面比例（16:9）+ 标题区约55px
        self._card_h = int(self._card_w * 9 / 16) + scale(55)
        self._opt_w = int(self._card_margin * 2 + self._cols * self._card_w + (self._cols - 1) * self._card_spacing)
        # 转整数供 setFixedSize / setGridSize 使用
        self._card_w_int = int(self._card_w)
        self._card_h_int = int(self._card_h)

    def resizeEvent(self, event):
        super().resizeEvent(event)
        if not hasattr(self, 'card_radio') or not self.card_radio.isChecked():
            return
        # 限制最大宽度不超过850
        max_w = scale(780)
        if self.width() > max_w:
            self._recalc_grid(max_w)
            self.resize(self._opt_w, self.height())
            return
        old_cols = getattr(self, '_cols', None)
        self._recalc_grid(self.width())
        if old_cols != self._cols or abs(self.width() - self._opt_w) > scale(8):
            self.resize(self._opt_w, self.height())


