    def copy_to_clipboard(self, text):
        try:
            clipboard = QApplication.clipboard()
            clipboard.setText(text)
        except Exception as e:
            logger.error(f"复制到剪贴板失败：{str(e)}")
    
    def _cancel_task(self, task_id):
        try:
            if self.download_manager:
                self.download_manager.cancel_task(task_id)
        except Exception as e:
            logger.error(f"取消任务失败：{str(e)}")

    def finish_episode(self, *args):
        try:
            self._finish_episode_impl(*args)
        except Exception:
            pass

    def _finish_episode_impl(self, *args):
        if len(args) == 4:
            task_id, ep_index, success, message = args
            if message == "TASK_PAUSED":
                return
            key = f"{task_id}_{ep_index}"
            if key in self.episode_map:
                bar_index = self.episode_map[key]
                if 0 <= bar_index < len(self.status_labels):
                    self.completed += 1
                    global_progress = min(100, int((self.completed / self.total_episodes) * 100))
                    self.global_progress.setValue(global_progress)

                    if success:
                        self.status_labels[bar_index].setText(f"√ 下载完成 - {message}")
                        self.status_labels[bar_index].setStyleSheet(scale_style("color: #52c41a; font-size: 12px;"))
                    else:
                        self.status_labels[bar_index].setText(f"× 失败：{message[:20]}...")
                        self.status_labels[bar_index].setStyleSheet(scale_style("color: #f56c6c; font-size: 12px;"))
                        self.failed.append(message)

                    parent = self.parent()
                    if parent and hasattr(parent, 'download_history'):
                        try:
                            bvid = self.video_info.get('bvid', '')
                            title = self.video_info.get('title', '未知视频')
                            url = f"https://www.bilibili.com/video/{bvid}" if bvid else ""
                            parent.download_history.add_record(
                                bvid=bvid, title=title, url=url,
                                status="success" if success else "failed",
                                error_msg="" if success else message[:200],
                            )
                        except Exception:
                            pass

                    all_completed = self.completed == self.total_episodes
                    if all_completed:
                        self.cancel_btn.setText("关闭窗口")
                        self.cancel_btn.clicked.disconnect()
                        self.cancel_btn.clicked.connect(self.close)

                        # 下载完成后将窗口置顶（比主界面层级高）
                        self.raise_()
                        self.activateWindow()

                        if self.failed:
                            msg = f"下载完成！\n成功：{self.total_episodes - len(self.failed)}集\n失败：{len(self.failed)}集"
                            parent = self.parent()
                            if parent and hasattr(parent, 'show_notification'):
                                parent.show_notification(msg, "warning")
                        else:
                            parent = self.parent()
                            if parent and hasattr(parent, 'show_notification'):
                                parent.show_notification("全部集数下载成功！", "success")
                        if parent and hasattr(parent, 'tray_icon') and parent.tray_icon:
                            try:
                                if self.failed:
                                    parent.tray_icon.showMessage("B站下载工具", f"下载完成！成功{self.total_episodes - len(self.failed)}集，失败{len(self.failed)}集", QSystemTrayIcon.Information, 5000)
                                else:
                                    parent.tray_icon.showMessage("B站下载工具", f"全部{self.total_episodes}集下载成功！", QSystemTrayIcon.Information, 5000)
                            except Exception:
                                pass
                        if parent and hasattr(parent, '_check_auto_shutdown') and parent._check_auto_shutdown():
                            QTimer.singleShot(3000, parent._do_auto_shutdown)
        elif len(args) == 3:
            index, success, message = args
            if message == "TASK_PAUSED":
                return
            if 0 <= index < len(self.status_labels):
                self.completed += 1
                global_progress = min(100, int((self.completed / self.total_episodes) * 100))
                self.global_progress.setValue(global_progress)

                if success:
                    self.status_labels[index].setText(f"√ 下载完成 - {message}")
                    self.status_labels[index].setStyleSheet(scale_style("color: #52c41a; font-size: 12px;"))
                else:
                    self.status_labels[index].setText(f"× 失败：{message[:20]}...")
                    self.status_labels[index].setStyleSheet(scale_style("color: #f56c6c; font-size: 12px;"))
                    self.failed.append(message)

                parent = self.parent()
                if parent and hasattr(parent, 'download_history'):
                    try:
                        bvid = self.video_info.get('bvid', '')
                        title = self.video_info.get('title', '未知视频')
                        url = f"https://www.bilibili.com/video/{bvid}" if bvid else ""
                        parent.download_history.add_record(
                            bvid=bvid, title=title, url=url,
                            status="success" if success else "failed",
                            error_msg="" if success else message[:200],
                        )
                    except Exception:
                        pass

                all_completed = self.completed == self.total_episodes
                if all_completed:
                    self.cancel_btn.setText("关闭窗口")
                    self.cancel_btn.clicked.disconnect()
                    self.cancel_btn.clicked.connect(self.close)

                    # 下载完成后将窗口置顶（比主界面层级高）
                    self.raise_()
                    self.activateWindow()

                    if self.failed:
                        msg = f"下载完成！\n成功：{self.total_episodes - len(self.failed)}集\n失败：{len(self.failed)}集"
                        parent = self.parent()
                        if parent and hasattr(parent, 'show_notification'):
                            parent.show_notification(msg, "warning")
                    else:
                        parent = self.parent()
                        if parent and hasattr(parent, 'show_notification'):
                            parent.show_notification("全部集数下载成功！", "success")
                    if parent and hasattr(parent, 'tray_icon') and parent.tray_icon:
                        try:
                            if self.failed:
                                parent.tray_icon.showMessage("B站下载工具", f"下载完成！成功{self.total_episodes - len(self.failed)}集，失败{len(self.failed)}集", QSystemTrayIcon.Information, 5000)
                            else:
                                parent.tray_icon.showMessage("B站下载工具", f"全部{self.total_episodes}集下载成功！", QSystemTrayIcon.Information, 5000)
                        except Exception:
                            pass
                    if parent and hasattr(parent, '_check_auto_shutdown') and parent._check_auto_shutdown():
                        QTimer.singleShot(3000, parent._do_auto_shutdown)

    def _update_global_progress(self, progress, message):
        try:
            self.global_progress.setValue(min(100, max(0, int(progress))))
            self.global_progress.setFormat(f"{int(progress)}%")
        except Exception:
            pass

    def on_cancel(self):
        self.cancel_all.emit()
        self.close()

    
    

    def toggle_maximize(self):
        
        if not self.isMaximized():
            self.showMaximized()

    def custom_close(self):
        self.window_closed.emit()
        self._close_with_animation()

    def closeEvent(self, event):
        try:
            self.window_closed.emit()
            self._close_with_animation()
        except Exception:
            pass
        event.ignore()

    def _close_with_animation(self):
        
        
        opacity = 1.0
        
        def fade_out():
            nonlocal opacity
            opacity -= 0.1
            if opacity >= 0:
                try:
                    self.setWindowOpacity(opacity)
                    QTimer.singleShot(30, fade_out)
                except RuntimeError:
                    
                    pass
            else:
                try:
                    self.hide()
                except RuntimeError:
                    
                    pass
        
        fade_out()


