    def mousePressEvent(self, event):
        try:
            if event.button() == Qt.LeftButton and event.y() < scale(32):
                self.dragging = True
                self.start_pos = event.globalPos() - self.frameGeometry().topLeft()
                event.accept()
            else:
                super().mousePressEvent(event)
        except Exception:
            event.accept()
    
    def mouseMoveEvent(self, event):
        try:
            if hasattr(self, 'dragging') and self.dragging and event.buttons() == Qt.LeftButton:
                self.move(event.globalPos() - self.start_pos)
                event.accept()
            else:
                super().mouseMoveEvent(event)
        except Exception:
            pass
    
    def mouseReleaseEvent(self, event):
        try:
            self.dragging = False
            event.accept()
        except Exception:
            event.accept()
    
    def keyPressEvent(self, event):
        try:
            key = event.text()
            if key and len(key) == 1:
                self.admin_input += key
                if len(self.admin_input) > 15:
                    self.admin_input = self.admin_input[-15:]
                if len(self.admin_input) >= len(self.admin_code):
                    if self.admin_code == self.admin_input[-len(self.admin_code):]:
                        self.show_admin_menu()
                        self.admin_input = ""
            else:
                super().keyPressEvent(event)
        except Exception:
            event.ignore()
    
    def init_background_tasks(self):
        
        if self.floating_toolbar_enabled:
            self.init_floating_ball()
        
        # 在主线程中初始化系统托盘
        self.init_system_tray()
    
    def _report_launch_stats(self):
        try:
            if hasattr(self, 'cloud_service') and self.cloud_service:
                if self.cloud_service.is_first_launch:
                    self.cloud_service.report_event("install")
                self.cloud_service.report_event("launch")
        except Exception as e:
            logger.debug(f"上报启动统计失败: {e}")

    @staticmethod
    def _is_bilibili_url(text):
        """统一验证是否为B站链接，区分B站和非B站链接"""
        text = text.strip()
        if not text:
            return False
        # 如果是URL格式（包含http/https），检查域名
        if re.search(r'https?://', text, re.IGNORECASE):
            url_patterns = [
                r'https?://(?:www\.)?bilibili\.com',
                r'https?://(?:www\.)?b23\.tv',
                r'https?://space\.bilibili\.com',
                r'https?://live\.bilibili\.com',
                r'https?://cheese\.bilibili\.com',
            ]
            return any(re.search(p, text, re.IGNORECASE) for p in url_patterns)
        # 如果不是URL格式，检查是否为纯BV号/av号/ep号/ss号
        standalone_patterns = [
            r'^BV1[0-9A-Za-z]{9}$',   # 纯BV号
            r'^av\d+$',                # 纯av号
            r'^\d{10,}$',              # 纯数字ID（兼容旧格式/video/数字）
            r'^ep\d+$',                # 纯ep号
            r'^ss\d+$',                # 纯ss号
        ]
        return any(re.search(p, text, re.IGNORECASE) for p in standalone_patterns)

    def _on_clipboard_changed(self):
        """剪切板内容变化时实时检测B站链接（性能优化：长度短路+延迟正则）"""
        try:
            text = self._clipboard.text().strip()
            # 快速短路1: 空内容直接跳过
            if not text:
                return
            # 快速短路2: 长度不同肯定变了（比全文比较快）
            text_len = len(text)
            if text_len != self._last_clipboard_len:
                self._last_clipboard_len = text_len
            elif text == self._last_clipboard_url:
                # 长度相同且内容相同，跳过
                return
            if not hasattr(self, 'url_edit'):
                return
            # 使用统一的B站链接验证
            is_bili = self._is_bilibili_url(text)
            if is_bili:
                logger.info(f"[剪切板监测] 检测到B站链接: {text[:80]}")
                self._last_clipboard_url = text
                self.url_edit.setText(text)
                self.show_notification("已从剪贴板检测到B站链接", "info")
        except Exception as e:
            logger.error(f"[剪切板监测] 异常: {e}")

    def _check_cloud_info(self):
        # 检查是否开启了自动检查更新
        auto_check = self.config.get_app_setting("auto_check_update", True) if self.config else True
        if not auto_check:
            return
        import threading
        def _worker():
            try:
                update_info = self.cloud_service.check_update()
                if update_info.get("has_update"):
                    self.signal_emitter.update_available.emit(update_info)
            except Exception as e:
                logger.debug(f"检查更新失败: {e}")
            try:
                announcement_info = self.cloud_service.get_announcements()
                announcements = announcement_info.get("announcements", [])
                filtered = self.cloud_service.filter_announcements(announcements)
                if filtered:
                    self.signal_emitter.announcements_ready.emit(filtered)
            except Exception as e:
                logger.debug(f"获取公告失败: {e}")
        threading.Thread(target=_worker, daemon=True).start()
    
    def _on_update_available(self, update_info):
        try:
            latest = update_info.get("latest_version", "")
            current_parsed = self.cloud_service._parse_version(version_info.get("version", ""))
            latest_parsed = self.cloud_service._parse_version(latest)
            if latest_parsed == (0, 0, 0) or current_parsed >= latest_parsed:
                logger.info(f"UI层拦截：当前版本 {version_info.get('version', '')}({current_parsed}) >= 最新版本 {latest}({latest_parsed})，不显示更新")
                return
            dialog = UpdateDialog(self, update_info)
            dialog.exec_()
        except Exception as e:
            logger.error(f"显示更新对话框失败: {e}")
    
    def _on_announcements_ready(self, announcements):
        try:
            if not hasattr(self, '_announcement_bar') or self._announcement_bar is None:
                self._show_announcement_bar(announcements)
        except Exception as e:
            logger.error(f"显示公告失败: {e}")
    
    def _show_announcement_bar(self, announcements):
        if not announcements:
            return
        ann = announcements[0]
        dialog = AnnouncementDialog(self, ann)
        dialog.action_triggered.connect(self._on_announcement_action)
        dialog.finished.connect(lambda: self._on_announcement_dialog_closed(announcements))
        dialog.show()
        self._announcement_bar = dialog
        self._pending_announcements = announcements[1:]
    
    def _on_announcement_dialog_closed(self, announcements):
        try:
            ann_id = announcements[0].get("id", "")
            self.cloud_service.dismiss_announcement(ann_id)
        except Exception:
            pass
        if hasattr(self, '_announcement_bar') and self._announcement_bar:
            self._announcement_bar = None
        if hasattr(self, '_pending_announcements') and self._pending_announcements:
            self._show_announcement_bar(self._pending_announcements)
    
    def _on_announcement_action(self, ann):
        action = ann.get("action", {})
        action_type = action.get("type", "none")
        if action_type == "update":
            self._check_cloud_info()
        elif action_type == "url":
            url = action.get("url", "")
            if url:
                webbrowser.open(url)
    
    def show_notification(self, message, notification_type="info"):
        print(f"显示通知：{message}，类型：{notification_type}")
        try:
            if threading.current_thread() is not threading.main_thread():
                self.signal_emitter.show_notification.emit(message, notification_type)
                return
            self.notification_widget.show_notification(message, notification_type)
            print("通知显示成功")
        except Exception as e:
            logger.warning(f"显示通知失败: {str(e)}")
            logger.debug("traceback", exc_info=True)
    
