    def show_debug_window(self, error_msg, code_context, file_path):
        logger.error("显示调试窗口 - 错误: %s | 文件: %s", error_msg, file_path)
        logger.error("代码上下文: %s", code_context)
        try:
            debug_window = DebugWindow(self)
            debug_window.set_error_info(error_msg, code_context, file_path)
            debug_window.show()
            debug_window.raise_()
            debug_window.activateWindow()
            logger.info("调试窗口显示成功")
        except Exception as e:
            logger.error("调试窗口显示失败: %s", str(e), exc_info=True)
    
    def check_proxy_settings(self):
        try:
            proxy = get_system_proxy()
            if proxy:
                # 确保代理字符串可以安全写入日志
                try:
                    safe_proxy = str(proxy).encode('utf-8', errors='replace').decode('utf-8')
                except Exception:
                    safe_proxy = "<代理信息包含非UTF-8字符>"
                logger.warning(f"检测到系统代理设置：{safe_proxy}")
                return True, safe_proxy
            
            # 检查环境变量中的代理设置
            http_proxy = os.environ.get('HTTP_PROXY') or os.environ.get('http_proxy')
            https_proxy = os.environ.get('HTTPS_PROXY') or os.environ.get('https_proxy')
            
            if http_proxy or https_proxy:
                logger.warning(f"检测到环境变量代理设置：HTTP={http_proxy}, HTTPS={https_proxy}")
                return True, f"HTTP={http_proxy}, HTTPS={https_proxy}"
            
            return False, None
        except Exception as e:
            logger.error(f"检查代理设置失败：{str(e)}")
            return False, None
    
