    def on_cookie_verified(self, success, msg):
        try:
            is_user_login = hasattr(self, '_cookie_login_btn') and self._cookie_login_btn is not None
            
            if hasattr(self, '_cookie_login_btn') and self._cookie_login_btn:
                self._cookie_login_btn.setEnabled(True)
                self._cookie_login_btn.setText("登录")
                self._cookie_login_btn = None
            
            if success:
                if hasattr(self, 'login_dialog') and self.login_dialog:
                    self.login_dialog.accept()
                    self.login_dialog = None
                
                if is_user_login:
                    self.show_notification(f"Cookie验证通过！{msg}", "success")
                self.hide_cookie_ui()
                
                import threading
                def post_login_tasks():
                    try:
                        user_info = self.parser.get_user_info(force_refresh=True)
                        self.signal_emitter.user_info_updated.emit(user_info)
                    except Exception as e:
                        logger.error(f"登录后处理失败：{str(e)}")
                
                thread = threading.Thread(target=post_login_tasks)
                thread.daemon = True
                thread.start()
            else:
                if is_user_login:
                    self.show_notification(f"Cookie验证失败：{msg}", "error")
                self.show_cookie_ui()
                self.user_info_label.setText("未登录")
                self.vip_label.setText("× 未登录")
                self.vip_label.setStyleSheet("color: #6b7280;")
                self.load_default_avatar()
                if hasattr(self, 'login_dialog') and self.login_dialog:
                    self.login_dialog.raise_()
        except Exception:
            pass
    
    def handle_verification_result(self, success, msg):
        """处理Cookie验证结果"""
        print("handle_verification_result函数开始执行")
        try:
            if success:
                try:
                    print("显示成功消息...")
                    self.show_success_message(msg)
                    print("成功消息已显示")
                    
                    if hasattr(self, 'login_dialog') and self.login_dialog:
                        print("隐藏登录对话框...")
                        self.login_dialog.hide()
                        print("登录对话框已隐藏")
                    
                    # 显示主窗口
                    self.showMaximized()
                    print("主窗口已显示")
                    
                    # 在子线程中加载用户信息，避免UI卡死
                    import threading
                    def load_user_info_in_thread():
                        try:
                            print("加载用户信息...")
                            user_info = self.parser.get_user_info(force_refresh=True)
                            print(f"获取到的用户信息：{user_info}")
                            self.signal_emitter.user_info_updated.emit(user_info)
                            print("登录后处理完成")
                        except Exception as e:
                            logger.error(f"加载用户信息失败：{str(e)}")
                            print(f"处理成功情况时发生异常：{str(e)}")
                            import traceback
                            logger.debug("traceback", exc_info=True)
                    
                    thread = threading.Thread(target=load_user_info_in_thread)
                    thread.daemon = True
                    thread.start()
                    
                except Exception as e:
                    logger.error(f"保存Cookie失败：{str(e)}")
                    self.show_notification(f"保存Cookie失败：{str(e)}", "error")
                    print(f"处理成功情况时发生异常：{str(e)}")
                    import traceback
                    logger.debug("traceback", exc_info=True)
            else:
                print("显示验证失败消息...")
                self.show_notification(f"验证失败：{msg}", "error")
                print("验证失败消息已显示")
                
                print("登录失败，保持窗口显示")
            
            print("验证流程执行完成")
        except Exception as e:
            print(f"handle_verification_result函数发生异常：{str(e)}")
            import traceback
            logger.debug("traceback", exc_info=True)
    
    def show_success_message(self, msg):
        self.show_notification(f"Cookie验证通过啦！\n{msg}", "success")
    
    def show_error_message(self, msg):
        self.show_notification(f"Cookie验证失败了：{msg}", "error")

    def on_parse(self):
        url = self.url_edit.text().strip()
        if not url:
            self.show_notification("请输入有效的视频链接", "warning")
            return
        # 验证是否为B站链接
        if not self._is_bilibili_url(url):
            self.show_notification("请输入B站链接（支持bilibili.com、b23.tv、BV号等）", "warning")
            return
        self.config.set_app_setting("last_parse_url", url)
        self.clear_parse_video_info()
        self.parse_btn.setEnabled(False)
        self.video_title.setText("解析中...")
        self.status_label.setText("正在解析链接...")
        
        # 创建解析进度窗口
        self.parse_progress_window = ParseProgressWindow(self)
        
        # 连接停止和取消信号
        self.parse_stopped = False
        self.parse_cancelled = False
        self.parse_progress_window.stop_signal.connect(self._on_parse_stop_requested)
        self.parse_progress_window.cancel_signal.connect(self._on_parse_cancel_requested)
        self.parse_progress_window.show()
        
        # 显示解析开始的通知
        self.show_notification("解析开始，正在处理视频信息...", "info")
        
        import threading
        
        # 读取权限不足重试次数配置
        perm_retry = self.config.get_app_setting("permission_denied_retries", 1)
        try:
            perm_retry = int(perm_retry)
        except Exception:
            perm_retry = 1
        
        def parse_in_thread():
            try:
                if self.parser is None:
                    self.signal_emitter.parse_finished.emit({"success": False, "error": "解析器未初始化，请重启应用"})
                    return
                
                def progress_callback(progress, message):
                    self.signal_emitter.parse_progress.emit(progress, message)
                
                # 检查是否已被取消
                if self.parse_cancelled:
                    return
                
                # 发送信号，在主线程中显示解析进度窗口
                self.signal_emitter.show_parse_progress.emit()
                
                # 发送进度更新信号（解析阶段进度条保持0%，只更新文字）
                progress_callback(0, "解析URL...")
                media_parse_video_info = self.parser.parse_media_url(url)
                if media_parse_video_info.get("error"):

                    self.signal_emitter.parse_finished.emit({"success": False, "error": media_parse_video_info["error"]})
                    return

                media_type = media_parse_video_info["type"]
                media_id = media_parse_video_info["id"]
                if not media_type or not media_id:
                    self.signal_emitter.parse_finished.emit({"success": False, "error": "未识别到有效媒体ID（支持BV/ss/av号）"})
                    return

                try:
                    if media_type == "live":
                        # 处理直播间链接：切换到直播Tab并填入房间号
                        progress_callback(0, "跳转到直播Tab...")
                        self.signal_emitter.parse_finished.emit({"success": True, "type": "live", "room_id": media_id, "message": "已切换到直播Tab"})
                        return

                    if media_type == "space":
                        # 处理 UP 主主页
                        progress_callback(0, "获取UP主信息...")
                        space_info = self.parser.get_space_info(media_id)
                        if not space_info.get("success"):
                            error_msg = space_info.get("error", "获取UP主信息失败")
                            if "访问权限不足" in error_msg:
                                error_msg = "该UP主主页可能需要登录或权限访问，请尝试登录后再解析"
                            self.signal_emitter.parse_finished.emit({"success": False, "error": error_msg})
                            return

                        def update_video_list_progress(msg):
                            progress_callback(0, msg)

                        def _cancel_check():
                            return self.parse_cancelled or self.parse_stopped

                        progress_callback(0, "获取UP主作品列表（首页）...")
                        videos_info = self.parser.get_space_videos(
                            media_id,
                            load_all=False,
                            cancel_check=_cancel_check,
                            progress_callback=update_video_list_progress
                        )
                        if not videos_info.get("success"):
                            error_msg = videos_info.get("error", "获取作品列表失败")
                            if "访问权限不足" in error_msg:
                                error_msg = "该UP主作品可能需要登录或权限访问，请尝试登录后再解析"
                            self.signal_emitter.parse_finished.emit({"success": False, "error": error_msg})
                            return

                        progress_callback(100, "加载完成！")
                        self.signal_emitter.show_space_videos.emit(space_info, videos_info)
                        return
                    else:
                        # 处理其他类型
                        # 传入权限不足重试次数
                        def _cancel_check():
                            return self.parse_cancelled or self.parse_stopped
                        media_info = self.parser.parse_media(media_type, media_id, False, progress_callback, permission_denied_retries=perm_retry, cancel_check=_cancel_check)
                        # 检查是否被停止或取消
                        if self.parse_cancelled:
                            return
                        if self.parse_stopped:
                            # 停止时如果有部分结果则显示（标记为部分结果）
                            if media_info.get("success"):
                                media_info["_partial"] = True
                                media_info["_stop_reason"] = "用户停止"
                            self.signal_emitter.parse_finished.emit(media_info)
                            return
                        self.signal_emitter.parse_finished.emit(media_info)
                except Exception as e:
                    self.signal_emitter.parse_finished.emit({"success": False, "error": f"解析失败：{str(e)}"})
            except Exception as e:
                self.signal_emitter.parse_finished.emit({"success": False, "error": f"解析失败：{str(e)}"})
        
        
        thread = threading.Thread(target=parse_in_thread)
        thread.daemon = True
        thread.start()
    
    def _on_parse_stop_requested(self):
        """用户点击停止按钮"""
        self.parse_stopped = True
        self.show_notification("正在停止解析，将保留已解析的结果...", "info")
    
    def _on_parse_cancel_requested(self):
        """用户点击取消按钮"""
        self.parse_cancelled = True
        self.show_notification("正在取消解析...", "warning")

    def clear_parse_video_info(self):
        self.video_title.setText("未解析")
        self.duration_label.setText("-")
        self.type_label.setText("未解析")
        self.type_label.setStyleSheet("")
        self.cover_label.setText("无封面")
        self.cover_label.setStyleSheet(scale_style("border: 1px solid #e2e8f0; border-radius: 8px; background-color: #f8fafc;"))
        
        video_info_group = self.findChild(QGroupBox, "video_info_group")
        if not video_info_group:
            
            for child in self.findChildren(QGroupBox):
                if child.title() in ("解析结果", "基本信息"):
                    video_info_group = child
                    break
        if video_info_group:
            video_info_group.setStyleSheet("")
        
        while hasattr(self, 'quality_combo') and self.quality_combo.count() > 1:
            self.quality_combo.removeItem(1)
        if hasattr(self, 'quality_combo'):
            self.quality_combo.setCurrentIndex(0)
            self.quality_combo.setEnabled(False)
        self._set_download_buttons_enabled(False)
        self.select_episode_btn.setEnabled(False)
        self.selected_episodes = []
        self.selected_qn = None
        self.select_episode_btn.setText("选择集数")

    def open_stream_player(self, url="", url_refresher=None):
        """打开流媒体播放器弹窗

        Args:
            url: 初始URL
            url_refresher: 可选回调函数，用于刷新过期的直播流URL。
                           签名: () -> str | None。返回最新URL或None。
        """
        try:
            from stream_player import StreamPlayerDialog
            if not self.stream_player_dialog:
                self.stream_player_dialog = StreamPlayerDialog(
                    config=self.config, parent=self, initial_url=url)
            # 设置URL刷新回调（用于B站直播流过期自动重试）
            if url_refresher:
                self.stream_player_dialog.set_url_refresher(url_refresher)
            if url:
                self.stream_player_dialog.play_url(url)
            else:
                self.stream_player_dialog.show()
                self.stream_player_dialog.raise_()
                self.stream_player_dialog.activateWindow()
        except Exception as e:
            logger.warning(f"打开流媒体播放器失败: {e}")
            QMessageBox.warning(self, "提示", f"流媒体播放器打开失败: {e}")

    def on_parse_finished(self, video_info):
        try:
            print(f"=== on_parse_finished被调用，video_info: {video_info}")

            # 处理直播间链接
            if video_info.get("type") == "live" and video_info.get("success"):
                room_id = video_info.get("room_id", "")
                if room_id and hasattr(self, 'live_tab') and self.live_tab:
                    # 切换到直播Tab
                    live_tab_index = self.tab_widget.indexOf(self.live_tab)
                    if live_tab_index >= 0:
                        self.tab_widget.setCurrentIndex(live_tab_index)
                    self.live_tab.room_id_input.setText(str(room_id))
                    self.live_tab._query_room_info()

                if hasattr(self, 'parse_progress_window') and self.parse_progress_window:
                    self.parse_progress_window.close()
                if hasattr(self, 'parse_btn'):
                    self.parse_btn.setEnabled(True)
                self.status_label.setText(f"已切换到直播Tab，房间号：{room_id}")
                self.show_notification("已切换到直播Tab", "info")
                return

            # 更新进度为100%并显示加载完成
            if hasattr(self, 'parse_progress_window') and self.parse_progress_window:
                QTimer.singleShot(0, lambda: self.parse_progress_window.update_progress(100, "加载完成"))
                # 延迟关闭窗口，让用户看到加载完成的提示
                QTimer.singleShot(1000, lambda: self.parse_progress_window.close())

            # 确保parse_btn存在
            if hasattr(self, 'parse_btn'):
                self.parse_btn.setEnabled(True)
            else:
                print("错误：parse_btn控件不存在")
            
            # 确保main_progress存在
            if hasattr(self, 'main_progress'):
                self.main_progress.setValue(0)
            else:
                print("错误：main_progress控件不存在")
            
            if not video_info.get("success"):
                error_msg = video_info.get("error", "未知错误")
                logger.warning(f"视频解析错误: {error_msg}")
                
                # 确保在主线程中更新UI
                QTimer.singleShot(0, lambda: self.update_ui_error(error_msg))
                return

            self.current_video_info = video_info
            
            # 判断是否为部分结果（用户停止）
            is_partial = video_info.get("_partial", False)
            episodes_count = len(video_info.get('episodes', [1]))
            
            if is_partial:
                print(f"解析（部分结果），标题：{video_info.get('title', '未知标题')}")
                stop_reason = video_info.get("_stop_reason", "用户停止")
                QTimer.singleShot(0, lambda: self.show_notification(
                    f"解析已停止，已获取 {episodes_count} 个视频结果（{stop_reason}）", "info"))
                if hasattr(self, 'status_label'):
                    self.status_label.setText(f"解析已停止 ({episodes_count} 个结果)")
            else:
                print(f"解析成功，标题：{video_info.get('title', '未知标题')}")
                QTimer.singleShot(0, lambda: self.show_notification(f"解析成功，共找到 {episodes_count} 个视频", "success"))
            
            # 确保在主线程中更新UI
            QTimer.singleShot(0, lambda: self.update_ui(video_info))
            
            QTimer.singleShot(0, lambda: self._populate_all_in_one_tab(video_info))
        except Exception as e:
            logger.error(f"更新视频信息UI异常: {e}")
            logger.debug("traceback", exc_info=True)
            # 关闭解析进度窗口
            if hasattr(self, 'parse_progress_window') and self.parse_progress_window:
                QTimer.singleShot(0, lambda: self.parse_progress_window.close())
            # 确保在主线程中显示通知
            QTimer.singleShot(0, lambda: self.show_notification(f"解析失败：{str(e)}", "error"))
    
    def on_show_space_videos(self, space_info, videos):
        try:
            self._on_show_space_videos_impl(space_info, videos)
        except Exception as e:
            logger.error(f"显示空间视频列表对话框失败：{str(e)}", exc_info=True)
            self.show_notification(f"显示视频列表失败：{str(e)}", "error")

    def _on_show_space_videos_impl(self, space_info, videos_info):
        # 先关闭解析进度模态窗口，否则新对话框会被它挡住无法显示
        if hasattr(self, 'parse_progress_window') and self.parse_progress_window:
            try:
                self.parse_progress_window.close()
            except Exception:
                pass

        class ImageLoader(QThread):
            image_ready = pyqtSignal(QLabel, QPixmap)
            
            def __init__(self, url, label):
                super().__init__()
                self.url = url
                self.label = label
            
            def run(self):
                try:
                    response = requests.get(self.url, headers=_COVER_HEADERS, timeout=10)
                    image = QImage()
                    success = image.loadFromData(response.content)
                    if success:
                        pixmap = QPixmap.fromImage(image)
                        self.image_ready.emit(self.label, pixmap)
                except Exception:
                    pass
        
        class ImageLoadManager:
            MAX_CONCURRENT = 5
            
            def __init__(self, dialog):
                self.dialog = dialog
                self.queue = []
                self.active_count = 0
            
            def enqueue(self, url, label):
                self.queue.append((url, label))
                self._try_next()
            
            def _try_next(self):
                while self.active_count < self.MAX_CONCURRENT and self.queue:
                    url, label = self.queue.pop(0)
                    self.active_count += 1
                    loader = ImageLoader(url, label)
                    self.dialog.loaders.append(loader)
                    def make_handler(l):
                        def handler(lb, pm):
                            self._on_loader_finished(l, lb, pm)
                        return handler
                    loader.image_ready.connect(make_handler(loader))
                    loader.start()
            
            def _on_loader_finished(self, loader, label, pixmap):
                self.active_count -= 1
                if loader in self.dialog.loaders:
                    self.dialog.loaders.remove(loader)
                try:
                    self.dialog.on_image_loaded(label, pixmap)
                except RuntimeError:
                    pass
                if self.queue:
                    self._try_next()
        

        
        class SpaceVideosDialog(QDialog):
            COL_CHECK = 0
            COL_INDEX = 1
            COL_TITLE = 2
            COL_DURATION = 3
            COL_PLAY = 4
            COL_QUALITY = 5
            COL_AUDIO = 6
            COL_ACTION = 7

            # 非模态模式下用信号通知父窗口用户选择了什么操作
            parse_action_requested = pyqtSignal(str, object)  # (action_type, data)

            class LoadWorker(QThread):
                finished = pyqtSignal(object)
                error = pyqtSignal(str)

                def __init__(self, parser, mid, page, ps, load_all=False):
                    super().__init__()
                    self.parser = parser
                    self.mid = mid
                    self.page = page
                    self.ps = ps
                    self.load_all = load_all

                def run(self):
                    try:
                        if self.load_all:
                            result = self.parser.get_space_videos(
                                self.mid, page=1, ps=self.ps, load_all=True
                            )
                        else:
                            result = self.parser.get_space_videos_page(
                                self.mid, page=self.page, ps=self.ps
                            )
                        self.finished.emit(result)
                    except Exception as e:
                        self.error.emit(str(e))

            def __init__(self, parent, space_info, videos_info):
                # 不传 parent 给 QDialog，使列表窗口成为独立窗口
                # 避免父窗口（最大化主窗口）遮挡子窗口，或模态时阻塞整个应用
                super().__init__(None)
                self.parent_widget = parent
                self.space_info = space_info
                self.mid = space_info.get('mid')
                self.videos = list(videos_info.get('videos', []))
                self.total = videos_info.get('total', len(self.videos))
                self.current_page = videos_info.get('page', 1)
                self.ps = videos_info.get('ps', 30)
                self._result_action = None
                self._parse_single_bvid = None
                self._parse_urls = []

                self.loaders = []
                self.image_manager = ImageLoadManager(self)
                self.locked_rows = set()
                self.loading = False
                self.downloading = False
                self._drag_pos = None

                self._init_ui()
                self._refresh_table()
                self._update_loaded_label()
                self._load_avatar()

