            def _update_header_checkbox_pos(self):
                header = self.table.horizontalHeader()
                x = header.sectionViewportPosition(0) + (header.sectionSize(0) - self.header_checkbox.width()) // 2
                y = (header.height() - self.header_checkbox.height()) // 2
                self.header_checkbox.move(x, y)

            def showEvent(self, event):
                super().showEvent(event)
                self._update_header_checkbox_pos()

