            def _load_avatar(self):
                face = self.space_info.get('face', '')
                if face:
                    self.image_manager.enqueue(face, self.avatar_label)

            def on_image_loaded(self, label, pixmap):
                if pixmap and label:
                    w = label.width()
                    h = label.height()
                    if w > 0 and h > 0:
                        pixmap = pixmap.scaled(w, h, Qt.KeepAspectRatio, Qt.SmoothTransformation)
                    label.setPixmap(pixmap)
                    label.setText("")
                    label.setStyleSheet("")

            def _refresh_table(self):
                self.table.blockSignals(True)
                self.table.clearContents()
                self.table.setRowCount(0)
                self.locked_rows.clear()

                for i, video in enumerate(self.videos):
                    self._add_video_row(i, video)

                self.table.blockSignals(False)
                self._update_selected_count()
                self._sync_header_checkbox()
                self._update_header_checkbox_pos()

            def _add_video_row(self, index, video):
                row = self.table.rowCount()
                self.table.insertRow(row)
                self.table.setRowHeight(row, scale(44))

                chk_item = QTableWidgetItem()
                chk_item.setFlags(Qt.ItemIsUserCheckable | Qt.ItemIsEnabled | Qt.ItemIsSelectable)
                chk_item.setCheckState(Qt.Unchecked)
                self.table.setItem(row, self.COL_CHECK, chk_item)

                idx_item = QTableWidgetItem(str(index + 1))
                idx_item.setTextAlignment(Qt.AlignCenter)
                self.table.setItem(row, self.COL_INDEX, idx_item)

                self.table.setCellWidget(row, self.COL_TITLE, self._create_title_widget(video))

                duration = video.get('duration', video.get('length', ''))
                if isinstance(duration, int):
                    duration = self._format_duration(duration)
                duration_item = QTableWidgetItem(str(duration))
                duration_item.setTextAlignment(Qt.AlignCenter)
                self.table.setItem(row, self.COL_DURATION, duration_item)

                play_item = QTableWidgetItem(str(video.get('play', '')))
                play_item.setTextAlignment(Qt.AlignCenter)
                self.table.setItem(row, self.COL_PLAY, play_item)

                q_combo = QComboBox()
                q_combo.setFixedWidth(scale(90))
                q_combo.setStyleSheet(scale_style("""
                    QComboBox {
                        border: 1px solid #d1d5db;
                        border-radius: 4px;
                        padding: 1px 4px;
                        font-size: 12px;
                    }
                """))
                self._fill_quality_combo(q_combo)
                q_combo.blockSignals(True)
                q_combo.setCurrentIndex(self.quality_combo.currentIndex())
                q_combo.blockSignals(False)
                q_combo.currentIndexChanged.connect(lambda _, r=row: self._on_row_quality_changed(r))
                self.table.setCellWidget(row, self.COL_QUALITY, q_combo)

                a_combo = QComboBox()
                a_combo.setFixedWidth(scale(100))
                a_combo.setStyleSheet(scale_style("""
                    QComboBox {
                        border: 1px solid #d1d5db;
                        border-radius: 4px;
                        padding: 1px 4px;
                        font-size: 12px;
                    }
                """))
                self._fill_audio_combo(a_combo)
                a_combo.blockSignals(True)
                a_combo.setCurrentIndex(self.audio_combo.currentIndex())
                a_combo.blockSignals(False)
                a_combo.currentIndexChanged.connect(lambda _, r=row: self._on_row_audio_changed(r))
                self.table.setCellWidget(row, self.COL_AUDIO, a_combo)

                self.table.setCellWidget(row, self.COL_ACTION, self._create_op_widget(video))

            def _format_duration(self, seconds):
                m, s = divmod(seconds, 60)
                h, m = divmod(m, 60)
                if h > 0:
                    return f"{h}:{m:02d}:{s:02d}"
                return f"{m}:{s:02d}"

            def _create_title_widget(self, video):
                widget = QWidget()
                layout = QHBoxLayout(widget)
                layout.setContentsMargins(scale(4), scale(2), scale(4), scale(2))
                layout.setSpacing(scale(6))

                cover_label = QLabel()
                cover_label.setFixedSize(scale(60), scale(34))
                cover_label.setStyleSheet(scale_style("background-color: #e2e8f0; border-radius: 2px;"))
                cover_label.setScaledContents(True)

                cover_url = video.get('pic', '')
                if cover_url:
                    self.image_manager.enqueue(cover_url, cover_label)

                title_label = QLabel(video.get('title', ''))
                title_label.setWordWrap(True)
                title_label.setStyleSheet(scale_style("font-size: 12px; color: #1e293b;"))

                layout.addWidget(cover_label)
                layout.addWidget(title_label, 1)

                return widget

            def _create_op_widget(self, video):
                widget = QWidget()
                layout = QHBoxLayout(widget)
                layout.setContentsMargins(scale(2), 0, scale(2), 0)
                layout.setSpacing(scale(4))

                parse_btn = QPushButton("解析")
                parse_btn.setFixedHeight(scale(24))
                parse_btn.setMinimumWidth(scale(52))
                parse_btn.setSizePolicy(QSizePolicy.Preferred, QSizePolicy.Fixed)
                parse_btn.setStyleSheet(scale_style("background-color: #409eff; color: white; border: none; border-radius: 4px; font-size: 11px; padding: 0 8px;"))
                parse_btn.clicked.connect(lambda: self._parse_single(video))

                cover_btn = QPushButton("下封面")
                cover_btn.setFixedHeight(scale(24))
                cover_btn.setMinimumWidth(scale(72))
                cover_btn.setSizePolicy(QSizePolicy.Preferred, QSizePolicy.Fixed)
                cover_btn.setStyleSheet(scale_style("background-color: #4f6ef7; color: white; border: none; border-radius: 4px; font-size: 11px; padding: 0 8px;"))
                cover_btn.clicked.connect(lambda: self._download_cover(video))

                layout.addWidget(parse_btn)
                layout.addWidget(cover_btn)
                layout.addStretch()

                return widget

            def _on_row_quality_changed(self, row):
                self.locked_rows.add(row)

            def _on_row_audio_changed(self, row):
                self.locked_rows.add(row)

            def _on_table_item_changed(self, item):
                if item.column() == self.COL_CHECK:
                    self._update_selected_count()
                    self._sync_header_checkbox()

            def _on_select_all_changed(self, state):
                self.header_checkbox.blockSignals(True)
                self.header_checkbox.setCheckState(state)
                self.header_checkbox.blockSignals(False)
                self._set_all_rows_checked(state == Qt.Checked)

            def _on_header_checkbox_changed(self, state):
                self.select_all_cb.blockSignals(True)
                self.select_all_cb.setCheckState(state)
                self.select_all_cb.blockSignals(False)
                self._set_all_rows_checked(state == Qt.Checked)

            def _set_all_rows_checked(self, checked):
                self.table.blockSignals(True)
                state = Qt.Checked if checked else Qt.Unchecked
                for row in range(self.table.rowCount()):
                    item = self.table.item(row, self.COL_CHECK)
                    if item:
                        item.setCheckState(state)
                self.table.blockSignals(False)
                self._update_selected_count()
                self._sync_header_checkbox()

            def _sync_header_checkbox(self):
                total = self.table.rowCount()
                checked = 0
                for row in range(total):
                    item = self.table.item(row, self.COL_CHECK)
                    if item and item.checkState() == Qt.Checked:
                        checked += 1

                self.header_checkbox.blockSignals(True)
                self.select_all_cb.blockSignals(True)
                if total > 0 and checked == total:
                    self.header_checkbox.setCheckState(Qt.Checked)
                    self.select_all_cb.setCheckState(Qt.Checked)
                elif checked > 0:
                    self.header_checkbox.setTristate(False)
                    self.select_all_cb.setTristate(False)
                    self.header_checkbox.setCheckState(Qt.Unchecked)
                    self.select_all_cb.setCheckState(Qt.Unchecked)
                else:
                    self.header_checkbox.setCheckState(Qt.Unchecked)
                    self.select_all_cb.setCheckState(Qt.Unchecked)
                self.header_checkbox.blockSignals(False)
                self.select_all_cb.blockSignals(False)

            def _update_selected_count(self):
                count = len(self._get_checked_rows())
                self.selected_count_label.setText(f"已选择 {count} 个视频")

            def _get_checked_rows(self):
                rows = []
                for row in range(self.table.rowCount()):
                    item = self.table.item(row, self.COL_CHECK)
                    if item and item.checkState() == Qt.Checked:
                        rows.append(row)
                return rows

            def _apply_to_selected(self):
                q_idx = self.quality_combo.currentIndex()
                a_idx = self.audio_combo.currentIndex()
                applied = 0
                for row in self._get_checked_rows():
                    if row in self.locked_rows:
                        continue
                    q_combo = self.table.cellWidget(row, self.COL_QUALITY)
                    a_combo = self.table.cellWidget(row, self.COL_AUDIO)
                    if q_combo:
                        q_combo.blockSignals(True)
                        q_combo.setCurrentIndex(q_idx)
                        q_combo.blockSignals(False)
                    if a_combo:
                        a_combo.blockSignals(True)
                        a_combo.setCurrentIndex(a_idx)
                        a_combo.blockSignals(False)
                    applied += 1
                if applied > 0:
                    self.parent_widget.show_notification(f"已应用到 {applied} 个未锁定的选中行", "success")
                else:
                    self.parent_widget.show_notification("没有可应用的未锁定选中行", "info")

            def _start_load(self, load_all):
                if self.loading:
                    return
                if not load_all and len(self.videos) >= self.total:
                    self.parent_widget.show_notification("没有更多视频了", "info")
                    return

                self.loading = True
                self._set_loading_ui(True)

                page = 1 if load_all else self.current_page + 1
                worker = self.LoadWorker(self.parent_widget.parser, self.mid, page, self.ps, load_all)
                worker.finished.connect(lambda result: self._on_load_finished(result, load_all))
                worker.error.connect(self._on_load_error)
                worker.finished.connect(worker.deleteLater)
                worker.error.connect(worker.deleteLater)
                worker.start()
                self.loaders.append(worker)

            def _set_download_buttons_enabled(self, enabled):
                for btn_name in ('download_btn', 'download_video_btn', 'download_audio_btn'):
                    if hasattr(self, btn_name):
                        getattr(self, btn_name).setEnabled(enabled)

            def _set_loading_ui(self, loading):
                self.loading = loading
                self.load_more_btn.setEnabled(not loading and len(self.videos) < self.total)
                self.load_all_btn.setEnabled(not loading)
                self.apply_btn.setEnabled(not loading)
                self._set_download_buttons_enabled(not loading and not self.downloading)
                self.parse_btn.setEnabled(not loading)
                if loading:
                    self.loaded_label.setText("加载中...")
                else:
                    self._update_loaded_label()

            def _on_load_finished(self, result, load_all):
                self.loading = False
                self._set_loading_ui(False)

                if not isinstance(result, dict):
                    self.parent_widget.show_notification("加载返回数据异常", "error")
                    return

                videos = result.get("videos", [])
                self.total = result.get("total", self.total)

                if load_all:
                    self.videos = videos
                    self.current_page = 1
                    self._refresh_table()
                else:
                    start_idx = len(self.videos)
                    self.videos.extend(videos)
                    self.current_page += 1
                    self.table.blockSignals(True)
                    for i, video in enumerate(videos):
                        self._add_video_row(start_idx + i, video)
                    self.table.blockSignals(False)
                    self._update_selected_count()
                    self._sync_header_checkbox()
                    self._update_header_checkbox_pos()

                self._update_loaded_label()
                self.load_more_btn.setVisible(len(self.videos) < self.total)

                if not videos and not load_all:
                    self.parent_widget.show_notification("没有加载到新视频", "info")

            def _on_load_error(self, error_msg):
                self.loading = False
                self._set_loading_ui(False)
                self.parent_widget.show_notification(f"加载失败: {error_msg}", "error")

            def _update_loaded_label(self):
                self.loaded_label.setText(f"已加载 {len(self.videos)} / 共 {self.total} 个")

            def _download_selected(self, content_type=0):
                selected_rows = self._get_checked_rows()
                if not selected_rows:
                    QMessageBox.information(self, "提示", "请先选择视频")
                    return

                self.downloading = True
                self._set_download_buttons_enabled(False)

                try:
                    selected_videos = []
                    first_qn = None
                    first_audio_qn = None

                    for idx, row in enumerate(selected_rows):
                        video = dict(self.videos[row])
                        q_combo = self.table.cellWidget(row, self.COL_QUALITY)
                        a_combo = self.table.cellWidget(row, self.COL_AUDIO)
                        qn = q_combo.currentData() if q_combo else self.get_selected_quality()
                        audio_qn = a_combo.currentData() if a_combo else self.get_selected_audio_quality()

                        if idx == 0:
                            first_qn = qn
                            first_audio_qn = audio_qn

                        video['_row_qn'] = qn
                        video['_row_audio_qn'] = audio_qn
                        video['_row_download_options'] = self.get_download_options()
                        video['_row_download_content_type'] = content_type
                        selected_videos.append(video)

                    # 启动异步下载（QThread，不因对话框状态而中断）
                    self.parent_widget.download_space_videos(
                        selected_videos, self.space_info, first_qn, first_audio_qn, content_type
                    )
                    self.parent_widget.show_notification(f"已开始下载 {len(selected_videos)} 个视频", "success")
                    # 保持列表窗口在前，不被批量下载窗口或主窗口遮挡
                    self.raise_()
                    self.activateWindow()
                except Exception as e:
                    self.parent_widget.show_notification(f"下载失败: {str(e)}", "error")
                    self.downloading = False
                    self._set_download_buttons_enabled(True)

            def _parse_selected(self):
                selected_rows = self._get_checked_rows()
                if not selected_rows:
                    QMessageBox.information(self, "提示", "请先选择视频")
                    return

                if len(selected_rows) == 1:
                    bvid = self.videos[selected_rows[0]].get('bvid', '')
                    self.parse_action_requested.emit('parse_single', bvid)
                else:
                    urls = []
                    for row in selected_rows:
                        bvid = self.videos[row].get('bvid', '')
                        if bvid:
                            urls.append(f"https://www.bilibili.com/video/{bvid}")
                    self.parse_action_requested.emit('parse_batch', urls)

            def _parse_single(self, video):
                bvid = video.get('bvid', '')
                self.parse_action_requested.emit('parse_single', bvid)

            def _download_cover(self, video):
                cover_url = video.get('pic', '')
                title = video.get('title', '')
                if not cover_url:
                    QMessageBox.information(self, "提示", "该视频没有封面信息")
                    return
                self.download_single_cover(cover_url, title)

            def download_single_cover(self, cover_url, title):
                safe_title = "".join(c for c in title if c.isalnum() or c in "_ -()[]（）【】") or "cover"
                save_path, _ = QFileDialog.getSaveFileName(
                    self, "保存封面", os.path.join(os.path.expanduser("~"), "Desktop", f"{safe_title}.png"),
                    "PNG图片 (*.png);;JPEG图片 (*.jpg);;BMP图片 (*.bmp);;所有文件 (*)"
                )
                if save_path:
                    def download():
                        try:
                            response = requests.get(cover_url, timeout=15)
                            response.raise_for_status()
                            with open(save_path, 'wb') as f:
                                f.write(response.content)
                            actual_save_path = save_path
                            if not os.path.exists(actual_save_path) or os.path.getsize(actual_save_path) == 0:
                                from utils import verify_and_ensure_save
                                actual_save_path, _cover_saved = verify_and_ensure_save(actual_save_path, content=response.content)
                                if not _cover_saved:
                                    raise Exception("封面保存验证失败")
                            self.parent_widget.show_notification(f"封面已保存到：{os.path.basename(actual_save_path)}", "success")
                        except Exception as e:
                            self.parent_widget.show_notification(f"保存失败：{str(e)}", "error")
                    threading.Thread(target=download, daemon=True).start()

            def _on_table_item_double_clicked(self, row, column):
                if row < 0 or row >= len(self.videos):
                    return
                video = self.videos[row]
                dialog = VideoDetailDialog(self, video, self.parent_widget)
                dialog.exec_()

