    def on_batch_download_covers(self):
        if not self.cover_data_list:
            self.show_notification("没有可下载的封面", "warning")
            return
        
        save_dir = QFileDialog.getExistingDirectory(self, "选择保存目录", os.path.expanduser("~"))
        if not save_dir:
            return
        
        self.show_notification("开始批量下载封面...", "info")
        
        import threading
        
        _task_manager = self.task_manager if hasattr(self, 'task_manager') else None
        
        def download_all():
            success_count = 0
            fail_count = 0
            for i, cover_data in enumerate(self.cover_data_list):
                try:
                    url = cover_data["url"]
                    title = cover_data.get("title", f"cover_{i+1}")
                    safe_title = "".join(c for c in title if c.isalnum() or c in "_ -()[]（）【】") or f"cover_{i+1}"
                    
                    response = requests.get(url, timeout=15)
                    response.raise_for_status()
                    
                    file_path = os.path.join(save_dir, f"{safe_title}.png")
                    with open(file_path, 'wb') as f:
                        f.write(response.content)
                    if not os.path.exists(file_path) or os.path.getsize(file_path) == 0:
                        from utils import verify_and_ensure_save
                        file_path, _cover_saved = verify_and_ensure_save(file_path, content=response.content)
                        if not _cover_saved:
                            raise Exception("封面保存验证失败")
                    success_count += 1
                    
                    if _task_manager:
                        task_id = f"cover_{int(time.time() * 1000)}_{i}"
                        _task_manager.add_task({
                            "id": task_id,
                            "url": url,
                            "title": safe_title,
                            "save_path": save_dir,
                            "status": "completed",
                            "progress": 100,
                            "task_type": "cover",
                            "cover_url": url,
                            "file_path": file_path,
                            "file_size": len(response.content),
                        })
                except Exception as e:
                    fail_count += 1
                    if _task_manager:
                        task_id = f"cover_{int(time.time() * 1000)}_{i}"
                        _task_manager.add_task({
                            "id": task_id,
                            "url": cover_data.get("url", ""),
                            "title": cover_data.get("title", f"cover_{i+1}"),
                            "save_path": save_dir,
                            "status": "failed",
                            "error_message": str(e),
                            "task_type": "cover",
                            "cover_url": cover_data.get("url", ""),
                        })
            
            def show_result():
                msg = f"批量下载完成：成功 {success_count} 个"
                if fail_count > 0:
                    msg += f"，失败 {fail_count} 个"
                self.show_notification(msg, "success" if fail_count == 0 else "warning")
            
            run_on_main_thread(show_result)
        
        thread = threading.Thread(target=download_all, daemon=True)
        thread.start()
    
